parameters:
{
  "sources": {
    "users": {
      "db": "stg",
      "table": "JsonPlaceholder_Users",
      "business_keys": [
        "user_id"
      ],
      "filter": {
        "where_clause": "CAST(stg_load_date AS DATE) > '{{LastRunDateTime}}' AND user_id IS NOT NULL"
      }
    },
    "todos": {
      "db": "stg",
      "table": "JsonPlaceholder_Todos",
      "business_keys": [
        "todo_id"
      ],
      "filter": {
        "where_clause": "CAST(stg_load_date AS DATE) > '{{LastRunDateTime}}' AND todo_id IS NOT NULL AND user_id IS NOT NULL"
      }
    }
  },
  "target": {
    "db": "int",
    "table": "User_Todo_Summary",
    "business_keys": [
      "User_ID"
    ],
    "write_mode": "truncate_insert"
  },
  "transformation": {
    "steps": [
      {
        "step_id": 10,
        "name": "read_users",
        "type": "read_source",
        "config": {
          "source_name": "users",
          "alias": "df_users"
        }
      },
      {
        "step_id": 20,
        "name": "dedup_users",
        "type": "deduplicate",
        "config": {
          "input_df": "df_users",
          "alias": "df_users_dedup",
          "use_source_business_keys": true,
          "source_name": "users",
          "order_by": [
            {
              "column": "stg_load_date",
              "direction": "desc"
            }
          ]
        }
      },
      {
        "step_id": 30,
        "name": "read_todos",
        "type": "read_source",
        "config": {
          "source_name": "todos",
          "alias": "df_todos"
        }
      },
      {
        "step_id": 40,
        "name": "dedup_todos",
        "type": "deduplicate",
        "config": {
          "input_df": "df_todos",
          "alias": "df_todos_dedup",
          "use_source_business_keys": true,
          "source_name": "todos",
          "order_by": [
            {
              "column": "stg_load_date",
              "direction": "desc"
            }
          ]
        }
      },
      {
        "step_id": 50,
        "name": "todo_flags",
        "type": "select",
        "config": {
          "input_df": "df_todos_dedup",
          "alias": "df_todo_flags",
          "columns": [
            {
              "expr": "user_id",
              "alias": "todo_user_id"
            },
            {
              "expr": "CASE WHEN is_completed THEN 1 ELSE 0 END",
              "alias": "completed_flag"
            }
          ]
        }
      },
      {
        "step_id": 60,
        "name": "aggregate_todos",
        "type": "aggregate",
        "config": {
          "input_df": "df_todo_flags",
          "alias": "df_todo_counts",
          "group_by": [
            "todo_user_id"
          ],
          "aggregations": [
            {
              "function": "count",
              "alias": "todo_count"
            },
            {
              "function": "sum",
              "column": "completed_flag",
              "alias": "completed_todo_count"
            }
          ]
        }
      },
      {
        "step_id": 70,
        "name": "join_users_to_todos",
        "type": "join",
        "config": {
          "left_df": "df_users_dedup",
          "right_df": "df_todo_counts",
          "alias": "df_joined",
          "join_type": "left",
          "on": [
            {
              "left": "user_id",
              "right": "todo_user_id"
            }
          ]
        }
      },
      {
        "step_id": 80,
        "name": "select_user_todo_summary",
        "type": "select",
        "config": {
          "input_df": "df_joined",
          "alias": "df_selected",
          "columns": [
            {
              "expr": "user_id",
              "alias": "User_ID"
            },
            {
              "expr": "display_name",
              "alias": "Display_Name"
            },
            {
              "expr": "username",
              "alias": "Username"
            },
            {
              "expr": "email",
              "alias": "Email"
            },
            {
              "expr": "coalesce(todo_count, 0)",
              "alias": "Todo_Count"
            },
            {
              "expr": "coalesce(completed_todo_count, 0)",
              "alias": "Completed_Todo_Count"
            },
            {
              "expr": "coalesce(todo_count, 0) - coalesce(completed_todo_count, 0)",
              "alias": "Open_Todo_Count"
            },
            {
              "expr": "stg_load_date",
              "alias": "stg_load_date"
            },
            {
              "expr": "batch_id",
              "alias": "batch_id"
            }
          ]
        }
      },
      {
        "step_id": 90,
        "name": "add_system_fields",
        "type": "add_system_fields",
        "config": {
          "input_df": "df_selected",
          "alias": "df_with_sys"
        }
      },
      {
        "step_id": 100,
        "name": "compute_hash",
        "type": "compute_hash",
        "config": {
          "input_df": "df_with_sys",
          "alias": "df_hashed"
        }
      },
      {
        "step_id": 110,
        "name": "write_target",
        "type": "write_target",
        "config": {
          "input_df": "df_hashed"
        }
      }
    ]
  }
}
